import{c as l,Q as i,j as r,g as e,n as t}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"出使德意志皇帝","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/120-出使德意志皇帝.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/120-出使德意志皇帝.md"}'),c={name:"research/machiavelli/machiavelli/diplomatic/lower/120-出使德意志皇帝.md"};function o(n,a,s,p,m,d){return i(),r("div",null,[...a[0]||(a[0]=[e("h1",{id:"出使德意志皇帝",tabindex:"-1"},[t("出使德意志皇帝 "),e("a",{class:"header-anchor",href:"#出使德意志皇帝","aria-label":'Permalink to "出使德意志皇帝"'},"​")],-1),e("p",null,"出使德意志皇帝 诸位大人能够施恩，让我回去。因为我身体不适，而且我留在这里对诸位 大人没有什么益处。因为如果诸位大人想和皇帝签订协议，那么可以派遣 已经选好的使臣前往这里。这样的话，可以为诸位大人争得更多荣誉和利 益。如果诸位大人不想签订协议，那么我留在这里的时间越长，对这件事 的讨论越多，就对诸位大人越不利。而且如果我留在宫廷，那么肯定要受 到别人的监控。那样，我给诸位大人提供的消息，也就不足为凭。所以， 考虑到所有这些因素，我留在这里实属多余。因此，我在此向诸位大人陈 情。为了让寄送这封信的信使能够骑上马匹快速前行，我已经付给他6达 克特和16个十字币。而且我还向他保证，这只是他的基本工钱，其他的要 视他的服务质量而定。",-1),e("p",null,"1508年6月8日，特伦特 仆弗朗切斯科 · 韦托里，大使",-1),e("p",null,"信件14",-1),e("p",null,"诸位大人钧鉴： 弗朗切斯科 · 韦托里于6月8日在特伦特给诸位大人写了一封信，并把 信件交由彼得罗(德意志人乔瓦尼的儿子)寄送。彼得罗承诺说，今天就 可以到达佛罗伦萨。那封信向诸位大人说明了休战协商的结论，还有直到 发信之日这里发生的其他事情。为了保险起见，弗朗切斯科把那封信的副 本交给了奥尔托拉诺(就是现在的这个信使)。我让他今天从这里出发， 这样诸位大人就可以早点知道弗朗切斯科让我口头向诸位大人报告的事 情。我因病滞留此处，无法前行。 我上周六(10日)离开特伦特。临走前的夜晚，我去见赛恩塔诺，请 他给我发放通行证。他告诉我，希望我们的大使能够在第二天早晨去拜访",-1),e("p",null,"Opere complete di Niccolò Machiavelli",-1)])])}const u=l(c,[["render",o]]);export{h as __pageData,u as default};
